+/// Append spec-decoding per-position acceptance rates like Python's logger.
+fn format_position_rates(output: &mut String, rates: &[f64]) {
+    for (position, rate) in rates.iter().enumerate() {
+        if position > 0 {
+            output.push_str(", ");
+        }
+        write!(output, "{rate:.3}").unwrap();
+    }
+}
